```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { ConfigService } from '@nestjs/config';
import { WhatsAppWebhookController } from '../../src/notifications/whatsapp-webhook.controller';
import { WhatsAppWebhookService } from '../../src/notifications/whatsapp-webhook.service';

describe('WhatsAppWebhookController', () => {
  let controller: WhatsAppWebhookController;
  let webhookService: {
    handleStatusUpdate: ReturnType<typeof vi.fn>;
    handleIncomingMessage: ReturnType<typeof vi.fn>;
  };
  let configGet: ReturnType<typeof vi.fn>;

  function makeConfig(values: Record<string, string | undefined> = {}) {
    configGet = vi.fn((key: string) => values[key]);
    return { get: configGet } as unknown as ConfigService;
  }

  function buildController(configValues: Record<string, string | undefined> = {}) {
    webhookService = {
      handleStatusUpdate: vi.fn().mockResolvedValue(undefined),
      handleIncomingMessage: vi.fn().mockResolvedValue(undefined),
    };
    const config = makeConfig(configValues);
    controller = new WhatsAppWebhookController(
      config,
      webhookService as unknown as WhatsAppWebhookService,
    );
  }

  beforeEach(() => {
    buildController();
  });

  // ── GET webhook verification ────────────────────────────────────────────

  describe('verify (GET)', () => {
    it('returns challenge when verify_token matches', () => {
      buildController({ WHATSAPP_VERIFY_TOKEN: 'sitebank-secret' });

      const result = controller.verify('subscribe', 'challenge-abc', 'sitebank-secret');

      expect(result).toBe('challenge-abc');
    });

    it('returns error when verify_token does not match', () => {
      buildController({ WHATSAPP_VERIFY_TOKEN: 'sitebank-secret' });

      const result = controller.verify('subscribe', 'challenge-abc', 'wrong-token');

      expect(result).toEqual({ error: 'Verification failed' });
    });

    it('returns error when mode is not subscribe', () => {
      buildController({ WHATSAPP_VERIFY_TOKEN: 'sitebank-secret' });

      const result = controller.verify('invalid', 'challenge-abc', 'sitebank-secret');

      expect(result).toEqual({ error: 'Verification failed' });
    });

    it('returns error when WHATSAPP_VERIFY_TOKEN is not configured', () => {
      buildController({});

      const result = controller.verify('subscribe', 'challenge-abc', 'anything');

      expect(result).toEqual({ error: 'Not configured' });
    });
  });

  // ── POST webhook event receiver ─────────────────────────────────────────

  describe('receive (POST)', () => {
    it('returns ok for empty body', async () => {
      const result = await controller.receive({}, '');

      expect(result).toEqual({ status: 'ok' });
    });

    it('returns ok when entries is empty array', async () => {
      const result = await controller.receive({ entry: [] }, '');

      expect(result).toEqual({ status: 'ok' });
    });

    it('processes status update from webhook', async () => {
      const statusObj = {
        id: 'wamid_123',
        status: 'delivered',
        timestamp: '1715000000',
      };

      const body = {
        entry: [
          {
            id: 'entry_1',
            changes: [
              {
                value: {
                  metadata: { display_phone_number: '15550001234' },
                  statuses: [statusObj],
                },
              },
            ],
          },
        ],
      };

      await controller.receive(body, '');

      expect(webhookService.handleStatusUpdate).toHaveBeenCalledTimes(1);
      expect(webhookService.handleStatusUpdate).toHaveBeenCalledWith(statusObj);
    });

    it('processes incoming message from webhook', async () => {
      const msgObj = {
        from: '919876543210',
        id: 'msg_test_1',
        type: 'text',
        text: { body: 'Hi, is this property still available?' },
      };

      const body = {
        entry: [
          {
            id: 'entry_1',
            changes: [
              {
                value: {
                  metadata: { display_phone_number: '15550001234' },
                  messages: [msgObj],
                },
              },
            ],
          },
        ],
      };

      await controller.receive(body, '');

      expect(webhookService.handleIncomingMessage).toHaveBeenCalledTimes(1);
      expect(webhookService.handleIncomingMessage).toHaveBeenCalledWith(
        msgObj,
        expect.objectContaining({
          metadata: { display_phone_number: '15550001234' },
        }),
      );
    });

    it('handles multiple entries with mixed messages and statuses', async () => {
      const body = {
        entry: [
          {
            id: 'entry_1',
            changes: [
              {
                value: {
                  statuses: [
                    { id: 'wamid_1', status: 'sent', timestamp: '1715000000' },
                  ],
                },
              },
            ],
          },
          {
            id: 'entry_2',
            changes: [
              {
                value: {
                  messages: [
                    {
                      from: '919876543210',
                      id: 'msg_2',
                      type: 'text',
                      text: { body: 'Hello' },
                    },
                  ],
                },
              },
            ],
          },
        ],
      };

      await controller.receive(body, '');

      expect(webhookService.handleStatusUpdate).toHaveBeenCalledTimes(1);
      expect(webhookService.handleIncomingMessage).toHaveBeenCalledTimes(1);
    });

    it('skips entries with no changes', async () => {
      const body = {
        entry: [{ id: 'entry_1', changes: [] }],
      };

      await controller.receive(body, '');

      expect(webhookService.handleStatusUpdate).not.toHaveBeenCalled();
      expect(webhookService.handleIncomingMessage).not.toHaveBeenCalled();
    });

    it('does not throw when handler fails (resilience)', async () => {
      webhookService.handleStatusUpdate.mockRejectedValue(new Error('DB error'));

      const body = {
        entry: [
          {
            id: 'entry_1',
            changes: [
              {
                value: {
                  statuses: [
                    { id: 'wamid_fail', status: 'delivered', timestamp: '1715000000' },
                  ],
                },
              },
            ],
          },
        ],
      };

      const result = await controller.receive(body, '');

      expect(result).toEqual({ status: 'ok' });
      expect(webhookService.handleStatusUpdate).toHaveBeenCalledTimes(1);
    });
  });
});
```

